import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { BaseClassTemplate } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums';
import { FormParent } from 'src/app/forms/userz.form';

@Component({
  selector: 'aam-parents-add',
  templateUrl: './parents-add.component.html',
  styleUrls: ['./parents-add.component.scss']
})
export class ParentAddComponent extends BaseClassTemplate implements OnInit {
  constructor(private route: ActivatedRoute) {
    super();
    this.param.ep = URLz.NO_SET
  }

  ngOnInit(): void {
    this._id = this.getQuery('id');
    FormParent(this);
    if (this._id != "null" && Number(this._id) > 0) {
      this.onEdit();
    } else {
      this._fs._form.removeControl("id");
    }
  }

  onEdit() {
    this._http
      .get({ ...this.param, resource: this._id })
      .subscribe((res: any) => {
        let data = res.data.row;
        FormParent(this, data);
      });
  }


}
