import { ChangeDetectionStrategy, Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { BaseClassTemplate } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums/url.enum';
import { FormAdmin } from 'src/app/forms/userz.form';

@Component({
  selector: 'aam-admin-add',
  templateUrl: './admin-add.component.html',
  styleUrls: ['./admin-add.component.scss'],
  host: {style: "width: 100% !important"},
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class AdminAddComponent extends BaseClassTemplate implements OnInit {
  constructor(private route: ActivatedRoute) {
    super();
    this.param.ep = URLz.NO_SET
  }

  ngOnInit(): void {
    this._id = this.getQuery('id');
    FormAdmin(this);
    if (this._id != "null" && Number(this._id) > 0) {
      this.onEdit();
    } else {
      this._fs._form.removeControl("id");
    }
  }

  onEdit() {
    this._http
      .get({ ...this.param, resource: this._id })
      .subscribe((res: any) => {
        let data = res.data.row;
        FormAdmin(this, data);
      });
  }

}
