import { Component, OnInit } from '@angular/core';
import { of } from 'rxjs';
import { DATA_DUMMY } from 'src/app/core';
import { BaseClassTemplate, LB } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums';

@Component({
  selector: 'aam-user-type',
  templateUrl: './user-type.component.html',
  styleUrls: ['./user-type.component.scss']
})
export class UserTypeComponent extends BaseClassTemplate implements OnInit {
  ngOnInit() {
    this.initTables();
  }
  initTables() {
    this.lb = new LB({
      isDummy: true,
      ep: URLz.$,
      query: this._fb.group({'is_advance': ['1']}).value,
    }, ['id','title','status','desc','createdAt','updatedAt', 'actions']);
    this.lb.beforeHit = () => {
      let records: any = DATA_DUMMY('User Type', 10);
      this.lb.ds.data = records
      this.lb.tbl.length = records.length;
      return of(this.lb);
    }
    this.lb.init();
    this.lb.refresh();
    this.lb.reset();
  }
}
